// Create two functions that work with object shapes:
// getRequiredKeys(schema: Record<string, boolean>): string[]
//   - Returns keys where value is true (meaning required)
// getOptionalKeys(schema: Record<string, boolean>): string[]
//   - Returns keys where value is false (meaning optional)

// Test with schema: { id: true, name: true, email: true, age: false, bio: false }
// Print required and optional keys

// Then create a validateObject function that checks if all required keys exist
// Test with a valid and invalid object

// Your code here

exercises.solution:
function getRequiredKeys(schema: Record<string, boolean>): string[] {
  return Object.entries(schema).filter(([_, required]) => required).map(([key]) => key);
}

function getOptionalKeys(schema: Record<string, boolean>): string[] {
  return Object.entries(schema).filter(([_, required]) => !required).map(([key]) => key);
}

function validateObject(obj: Record<string, any>, schema: Record<string, boolean>): { valid: boolean; missing: string[] } {
  const required = getRequiredKeys(schema);
  const missing = required.filter(key => !(key in obj));
  return { valid: missing.length === 0, missing };
}

const schema = { id: true, name: true, email: true, age: false, bio: false };

console.log(`Required: ${getRequiredKeys(schema).join(', ')}`);
console.log(`Optional: ${getOptionalKeys(schema).join(', ')}`);

const valid = validateObject({ id: 1, name: 'Alice', email: 'a@b.com', age: 30 }, schema);
console.log(`Valid object: ${valid.valid}, missing: [${valid.missing.join(', ')}]`);

const invalid = validateObject({ id: 2, name: 'Bob' }, schema);
console.log(`Invalid object: ${invalid.valid}, missing: [${invalid.missing.join(', ')}]`);

