// Create function deepGet(obj: any, path: string): any
// Splits path by '.' and navigates nested properties
// Returns undefined if any intermediate property is missing

// Create function deepSet(obj: any, path: string, value: any): any
// Creates a new object with the nested property set
// Creates intermediate objects if they don't exist

// Test:
// const data = { user: { profile: { name: 'Alice', settings: { theme: 'dark' } } } }
// deepGet(data, 'user.profile.name') -> 'Alice'
// deepGet(data, 'user.profile.settings.theme') -> 'dark'
// deepGet(data, 'user.missing.path') -> undefined

// Your code here

exercises.solution:
function deepGet(obj: any, path: string): any {
  const keys = path.split('.');
  let current = obj;
  for (const key of keys) {
    if (current === null || current === undefined) return undefined;
    current = current[key];
  }
  return current;
}

function deepSet(obj: any, path: string, value: any): any {
  const keys = path.split('.');
  if (keys.length === 1) {
    return { ...obj, [keys[0]]: value };
  }
  const [first, ...rest] = keys;
  return {
    ...obj,
    [first]: deepSet(obj[first] || {}, rest.join('.'), value)
  };
}

const data = { user: { profile: { name: 'Alice', settings: { theme: 'dark' } } } };

console.log(deepGet(data, 'user.profile.name'));
console.log(deepGet(data, 'user.profile.settings.theme'));
console.log(deepGet(data, 'user.missing.path'));

const updated = deepSet(data, 'user.profile.settings.theme', 'light');
console.log(deepGet(updated, 'user.profile.settings.theme'));

const withNew = deepSet(data, 'user.profile.avatar', 'pic.jpg');
console.log(deepGet(withNew, 'user.profile.avatar'));

