// Create function actualType(value: any): string
// Return the precise type:
// null -> 'null' (not 'object')
// undefined -> 'undefined'
// NaN -> 'NaN' (not 'number')
// arrays -> 'array' (not 'object')
// dates -> 'date' (not 'object')
// regex -> 'regexp' (not 'object')
// everything else -> typeof result

// Test with: null, undefined, NaN, 42, 'hello', true, [1,2], new Date(), /abc/, {}, function(){}

// Your code here

exercises.solution:
function actualType(value: any): string {
  if (value === null) return 'null';
  if (value === undefined) return 'undefined';
  if (typeof value === 'number' && isNaN(value)) return 'NaN';
  if (Array.isArray(value)) return 'array';
  if (value instanceof Date) return 'date';
  if (value instanceof RegExp) return 'regexp';
  return typeof value;
}

const testValues: [any, string][] = [
  [null, 'null'],
  [undefined, 'undefined'],
  [NaN, 'NaN'],
  [42, 'number'],
  ['hello', 'string'],
  [true, 'boolean'],
  [[1, 2], 'array'],
  [new Date(), 'date'],
  [/abc/, 'regexp'],
  [{}, 'object'],
  [function(){}, 'function']
];

testValues.forEach(([value, _]) => {
  console.log(actualType(value));
});

