// Create a QueryBuilder class that builds SQL-like query strings:
// select(fields: string[]): this
// from(table: string): this
// where(condition: string): this
// orderBy(field: string, direction: 'ASC' | 'DESC'): this
// limit(count: number): this
// build(): string

// Test:
// Build: SELECT name, email FROM users WHERE active = true ORDER BY name ASC LIMIT 10
// Build: SELECT * FROM products

// Your code here

exercises.solution:
class QueryBuilder {
  private fields: string[] = [];
  private table: string = '';
  private conditions: string[] = [];
  private ordering: string = '';
  private limitCount: number | null = null;

  select(fields: string[]): this {
    this.fields = fields;
    return this;
  }

  from(table: string): this {
    this.table = table;
    return this;
  }

  where(condition: string): this {
    this.conditions.push(condition);
    return this;
  }

  orderBy(field: string, direction: 'ASC' | 'DESC'): this {
    this.ordering = `${field} ${direction}`;
    return this;
  }

  limit(count: number): this {
    this.limitCount = count;
    return this;
  }

  build(): string {
    const parts: string[] = [];
    parts.push(`SELECT ${this.fields.length > 0 ? this.fields.join(', ') : '*'}`);
    parts.push(`FROM ${this.table}`);
    if (this.conditions.length > 0) {
      parts.push(`WHERE ${this.conditions.join(' AND ')}`);
    }
    if (this.ordering) {
      parts.push(`ORDER BY ${this.ordering}`);
    }
    if (this.limitCount !== null) {
      parts.push(`LIMIT ${this.limitCount}`);
    }
    return parts.join(' ');
  }
}

const query1 = new QueryBuilder()
  .select(['name', 'email'])
  .from('users')
  .where('active = true')
  .orderBy('name', 'ASC')
  .limit(10)
  .build();

console.log(query1);

const query2 = new QueryBuilder()
  .select([])
  .from('products')
  .build();

console.log(query2);

