// Define a FormatStrategy interface: { format(text: string): string }
// Implement strategies: UpperCase, LowerCase, TitleCase, SnakeCase
// Create a TextFormatter class that accepts a strategy and can switch strategies

// Test:
// Format 'hello world typescript' with each strategy

// Your code here

exercises.solution:
interface FormatStrategy {
  format(text: string): string;
}

class UpperCaseStrategy implements FormatStrategy {
  format(text: string): string {
    return text.toUpperCase();
  }
}

class LowerCaseStrategy implements FormatStrategy {
  format(text: string): string {
    return text.toLowerCase();
  }
}

class TitleCaseStrategy implements FormatStrategy {
  format(text: string): string {
    return text.split(' ').map(word => word.charAt(0).toUpperCase() + word.slice(1).toLowerCase()).join(' ');
  }
}

class SnakeCaseStrategy implements FormatStrategy {
  format(text: string): string {
    return text.toLowerCase().split(' ').join('_');
  }
}

class TextFormatter {
  constructor(private strategy: FormatStrategy) {}

  setStrategy(strategy: FormatStrategy): void {
    this.strategy = strategy;
  }

  format(text: string): string {
    return this.strategy.format(text);
  }
}

const formatter = new TextFormatter(new UpperCaseStrategy());
const text = 'hello world typescript';

console.log(formatter.format(text));

formatter.setStrategy(new LowerCaseStrategy());
console.log(formatter.format(text));

formatter.setStrategy(new TitleCaseStrategy());
console.log(formatter.format(text));

formatter.setStrategy(new SnakeCaseStrategy());
console.log(formatter.format(text));

