// Create function findExcessProperties(obj: Record<string, any>, allowedKeys: string[]): string[]
// Return keys in obj that are NOT in allowedKeys

// Create function strictAssign<T>(target: Record<string, any>, allowedKeys: string[]): Record<string, any>
// Return a new object with only the allowed keys

// Test:
// obj = { name: 'Alice', age: 30, email: 'alice@test.com', debug: true }
// allowedKeys = ['name', 'age', 'email']
// Find excess properties and create a strict object

// Your code here

exercises.solution:
function findExcessProperties(obj: Record<string, any>, allowedKeys: string[]): string[] {
  return Object.keys(obj).filter(key => !allowedKeys.includes(key));
}

function strictAssign(obj: Record<string, any>, allowedKeys: string[]): Record<string, any> {
  const result: Record<string, any> = {};
  for (const key of allowedKeys) {
    if (key in obj) {
      result[key] = obj[key];
    }
  }
  return result;
}

const obj = { name: 'Alice', age: 30, email: 'alice@test.com', debug: true };
const allowedKeys = ['name', 'age', 'email'];

const excess = findExcessProperties(obj, allowedKeys);
console.log(`Excess properties: ${excess.join(', ')}`);

const strict = strictAssign(obj, allowedKeys);
console.log(`Strict object: ${JSON.stringify(strict)}`);
console.log(`Original keys: ${Object.keys(obj).length}`);
console.log(`Strict keys: ${Object.keys(strict).length}`);

