// Create a TypeTracker class that simulates type inference:
// infer(value: any): string - returns the inferred type
//   For 'let' style: widen (e.g., 'hello' -> 'string', 42 -> 'number')
//   For literal values, return the literal type as a string
// narrow(value: any, check: string): string - returns narrowed type
//   check can be: 'string', 'number', 'truthy', 'nonnull'

// Test with various values showing widening and narrowing

// Your code here

exercises.solution:
class TypeTracker {
  inferWidened(value: any): string {
    if (value === null) return 'null';
    if (value === undefined) return 'undefined';
    if (Array.isArray(value)) {
      const types = [...new Set(value.map((v: any) => typeof v))];
      return `(${types.join(' | ')})[]`;
    }
    return typeof value;
  }

  inferLiteral(value: any): string {
    if (value === null) return 'null';
    if (value === undefined) return 'undefined';
    if (typeof value === 'string') return `'${value}'`;
    if (typeof value === 'number') return `${value}`;
    if (typeof value === 'boolean') return `${value}`;
    return typeof value;
  }

  narrow(currentType: string, check: string): string {
    if (check === 'truthy') return currentType.replace(' | null', '').replace(' | undefined', '');
    if (check === 'nonnull') return currentType.replace(' | null', '');
    return check;
  }
}

const tracker = new TypeTracker();

// Widening (let-style)
console.log(`let x = 'hello' -> ${tracker.inferWidened('hello')}`);
console.log(`let y = 42 -> ${tracker.inferWidened(42)}`);
console.log(`let z = true -> ${tracker.inferWidened(true)}`);

// Literal (const-style)
console.log(`const a = 'hello' -> ${tracker.inferLiteral('hello')}`);
console.log(`const b = 42 -> ${tracker.inferLiteral(42)}`);

// Narrowing
console.log(`string | number narrowed by 'string' -> ${tracker.narrow('string | number', 'string')}`);
console.log(`string | null narrowed by 'nonnull' -> ${tracker.narrow('string | null', 'nonnull')}`);

