function parseJSON<T>(input: string): T | null {
  try {
    return JSON.parse(input) as T;
  } catch {
    return null;
  }
}

function merge<A extends Record<string, unknown>, B extends Record<string, unknown>>(a: A, b: B): A & B {
  return { ...a, ...b } as A & B;
