// Create interface FileInfo:
// { name: string, extension: 'js' | 'ts', imports: string[], complexity: number }

// Create function planMigration(files: FileInfo[]): string[]
// Return JS files in migration order:
// 1. Files with no imports from other JS files first (leaf nodes)
// 2. Then files whose dependencies are already migrated
// 3. Sort by complexity (lower first) within each tier

// Test with a set of files

// Your code here

exercises.solution:
interface FileInfo {
  name: string;
  extension: 'js' | 'ts';
  imports: string[];
  complexity: number;
}

function planMigration(files: FileInfo[]): string[] {
  const jsFiles = files.filter(f => f.extension === 'js');
  const tsFiles = new Set(files.filter(f => f.extension === 'ts').map(f => f.name));
  const migrated = new Set<string>(tsFiles);
  const order: string[] = [];
  const remaining = new Set(jsFiles.map(f => f.name));

  while (remaining.size > 0) {
    const ready = jsFiles
      .filter(f => remaining.has(f.name))
      .filter(f => f.imports.every(imp => migrated.has(imp) || !remaining.has(imp)))
      .sort((a, b) => a.complexity - b.complexity);

    if (ready.length === 0) {
      // Circular dependency - take the least complex
      const fallback = jsFiles
        .filter(f => remaining.has(f.name))
        .sort((a, b) => a.complexity - b.complexity);
      if (fallback.length > 0) {
        order.push(fallback[0].name);
        migrated.add(fallback[0].name);
        remaining.delete(fallback[0].name);
      }
      continue;
    }

    for (const file of ready) {
      order.push(file.name);
      migrated.add(file.name);
      remaining.delete(file.name);
    }
  }

  return order;
}

const files: FileInfo[] = [
  { name: 'utils', extension: 'js', imports: [], complexity: 2 },
  { name: 'types', extension: 'ts', imports: [], complexity: 1 },
  { name: 'api', extension: 'js', imports: ['utils', 'types'], complexity: 5 },
  { name: 'helpers', extension: 'js', imports: ['utils'], complexity: 3 },
  { name: 'app', extension: 'js', imports: ['api', 'helpers'], complexity: 8 }
];

const plan = planMigration(files);
console.log('Migration order:');
plan.forEach((name, i) => console.log(`${i + 1}. ${name}`));
console.log(`Total files to migrate: ${plan.length}`);
